import { AboutStaticScreen } from '../screens/AboutStaticScreen';

// Dans votre Stack.Navigator :
<Stack.Screen
  name="About"
  component={AboutStaticScreen}
  options={{ title: 'À propos', headerShown: true }}
/>

useEffect(() => {
  const loadProduct = async () => {
    const data = await fetchProductById(productId);
    setProduct(data);

    // ✅ Mettre à jour les meta tags
    setProductPageMeta({
      productId: data.id,
      name: data.name,
      description: data.description,
      price: data.price,
      rating: data.rating,
      ratingCount: data.review_count,
      imageUrl: data.primary_image_url,
      inStock: data.quantity > 0,
      currency: 'XOF',
    });
  };
  loadProduct();
}, [productId]);

return (
  <>
    {product && (
      <ProductSchema
        product={{
          id: product.id,
          name: product.name,
          description: product.description,
          price: product.price,
          rating: product.rating,
          ratingCount: product.review_count,
          imageUrl: product.primary_image_url,
          inStock: product.quantity > 0,
          slug: product.slug,
          sku: product.sku,
        }}
      />
    )}
    {/* Votre contenu existant */}
  </>
);

useEffect(() => {
  const loadStore = async () => {
    const data = await fetchStoreById(storeId);
    setStore(data);

    // ✅ Mettre à jour les meta tags
    setStorePageMeta({
      storeId: data.id,
      storeName: data.name,
      description: data.description,
      imageUrl: data.logo_url,
      rating: data.rating,
      ratingCount: data.review_count,
      location: data.city,
    });
  };
  loadStore();
}, [storeId]);

return (
  <>
    {store && (
      <StoreSchema
        store={{
          id: store.id,
          name: store.name,
          description: store.description,
          imageUrl: store.logo_url,
          rating: store.rating,
          ratingCount: store.review_count,
          location: store.city,
          slug: store.slug,
        }}
      />
    )}
    {/* Votre contenu existant */}
  </>
);
